interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





// Color map for element categories
const getCategoryColor = (category: string | undefined): string => {
  const colorMap: Record<string, string> = {
    'noble gas': 'var(--ggui-color-info-100)',
    'halogen': 'var(--ggui-color-warning-100)',
    'alkali metal': 'var(--ggui-color-error-100)',
    'alkaline earth metal': 'var(--ggui-color-success-100)',
    'transition metal': 'var(--ggui-color-primary-100)',
    'lanthanide': 'var(--ggui-color-primary-200)',
    'actinide': 'var(--ggui-color-primary-300)',
    'metalloid': 'var(--ggui-color-warning-200)',
    'nonmetal': 'var(--ggui-color-info-200)',
    'metal': 'var(--ggui-color-neutral-200)',
  };
  return colorMap[category?.toLowerCase() || ''] || 'var(--ggui-color-surfaceVariant)';
};

// Get text color for category
const getCategoryTextColor = (category: string | undefined): string => {
  const darkCategories = ['noble gas', 'halogen', 'transition metal', 'nonmetal'];
  if (category && darkCategories.some(c => c.toLowerCase() === category.toLowerCase())) {
    return 'var(--ggui-color-onSurfaceVariant)';
  }
  return 'var(--ggui-color-onSurface)';
};

export default function Component(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<(typeof props.elements)[0] | null>(null);

  // Filter elements by search query
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query)
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const uniqueCategories = new Set<string>();
    props.elements.forEach((el) => {
      if (el.category) uniqueCategories.add(el.category);
    });
    return Array.from(uniqueCategories).sort();
  }, [props.elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Title */}
        <Heading level={1}>Periodic Table of Elements</Heading>

        {/* Search Bar */}
        <SearchField
          value={searchQuery}
          onChange={setSearchQuery}
          placeholder="Search by name or symbol..."
          size="md"
        />

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Legend</Heading>
            <Row gap="var(--ggui-spacing-4)" wrap>
              {categories.map((category) => (
                <Row key={category} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    background={getCategoryColor(category)}
                    borderRadius="var(--ggui-shape-radius-sm)"
                    padding="var(--ggui-spacing-1)"
                    style={{ minWidth: '20px', minHeight: '20px' }}
                  />
                  <Text variant="label" color="var(--ggui-color-onSurface)">
                    {category}
                  </Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2)',
            marginBottom: 'var(--ggui-spacing-6)',
          }}
        >
          {filteredElements.map((element) => (
            <Card
              key={`${element.atomicNumber}`}
              padding="var(--ggui-spacing-2)"
              shadow="sm"
              as={Clickable}
              onClick={() => setSelectedElement(element)}
              style={{
                gridRow: element.row,
                gridColumn: element.col,
                background: getCategoryColor(element.category),
                cursor: 'pointer',
                transition: 'all 200ms ease-in-out',
              }}
              hoverStyle={{
                opacity: 0.8,
                boxShadow: 'var(--ggui-shape-shadow-md)',
              }}
            >
              <Stack gap="var(--ggui-spacing-1)" align="center">
                {/* Atomic Number - Top Left */}
                <Text
                  variant="caption"
                  color={getCategoryTextColor(element.category)}
                  align="left"
                  style={{ alignSelf: 'flex-start', fontSize: 'var(--ggui-font-size-xs)' }}
                >
                  {element.atomicNumber}
                </Text>
                {/* Symbol - Large Center */}
                <Text
                  variant="label"
                  weight="bold"
                  size="lg"
                  color={getCategoryTextColor(element.category)}
                  align="center"
                >
                  {element.symbol}
                </Text>
                {/* Name - Small Below */}
                <Text
                  variant="caption"
                  color={getCategoryTextColor(element.category)}
                  align="center"
                  size="xs"
                  truncate
                >
                  {element.name}
                </Text>
              </Stack>
            </Card>
          ))}
        </Box>

        {/* Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Row justify="between" align="center">
                <Heading level={2}>{selectedElement.name}</Heading>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                >
                  Close
                </Button>
              </Row>
              <Divider margin="var(--ggui-spacing-2)" />
              <Stack gap="var(--ggui-spacing-3)">
                <Row gap="var(--ggui-spacing-4)">
                  <Box flex="1">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Symbol
                    </Text>
                    <Text size="lg" weight="bold" color="var(--ggui-color-onSurface)">
                      {selectedElement.symbol}
                    </Text>
                  </Box>
                  <Box flex="1">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Atomic Number
                    </Text>
                    <Text size="lg" weight="bold" color="var(--ggui-color-onSurface)">
                      {selectedElement.atomicNumber}
                    </Text>
                  </Box>
                  <Box flex="1">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Atomic Weight
                    </Text>
                    <Text size="lg" weight="bold" color="var(--ggui-color-onSurface)">
                      {selectedElement.atomicWeight?.toFixed(2) || 'N/A'}
                    </Text>
                  </Box>
                </Row>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Category
                  </Text>
                  <Badge
                    variant="primary"
                    size="md"
                    style={{
                      background: getCategoryColor(selectedElement.category),
                      color: getCategoryTextColor(selectedElement.category),
                      marginTop: 'var(--ggui-spacing-1)',
                    }}
                  >
                    {selectedElement.category || 'Unknown'}
                  </Badge>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Empty State */}
        {filteredElements.length === 0 && (
          <Alert variant="info">
            No elements found matching "{searchQuery}". Try a different search.
          </Alert>
        )}
      </Stack>
    </Container>
  );
}

