// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State management
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Helper: validate quantity is within bounds
  const handleQuantityChange = useCallback((newQty: number) => {
    const maxStock = props.product.stock || 0;
    const bounded = Math.max(1, Math.min(newQty, maxStock));
    setQuantity(bounded);
  }, [props.product.stock]);

  // Helper: decrement quantity
  const decrementQty = useCallback(() => {
    handleQuantityChange(quantity - 1);
  }, [quantity, handleQuantityChange]);

  // Helper: increment quantity
  const incrementQty = useCallback(() => {
    handleQuantityChange(quantity + 1);
  }, [quantity, handleQuantityChange]);

  // Helper: format price with currency
  const formattedPrice = useMemo(() => {
    const symbol = props.product.currency || 'USD';
    const price = props.product.price ?? 0;
    // Simple currency symbol mapping
    const currencySymbols: Record<string, string> = {
      USD: '$',
      EUR: '€',
      GBP: '£',
      JPY: '¥',
      CAD: 'C$',
      AUD: 'A$',
    };
    const sym = currencySymbols[symbol] || symbol;
    return `${sym}${price.toFixed(2)}`;
  }, [props.product.price, props.product.currency]);

  // Helper: render rating stars
  const renderStars = (rating: number | undefined) => {
    if (!rating) return null;
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      const filled = i <= Math.floor(rating);
      stars.push(
        <Icon
          key={i}
          name="star"
          size={16}
          color={filled ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
        />
      );
    }
    return <Row gap="var(--ggui-spacing-1)" align="center">{stars}</Row>;
  };

  // Helper: determine stock status
  const stockStatus = useMemo(() => {
    const stock = props.product.stock ?? 0;
    if (stock === 0) return { label: 'Out of Stock', variant: 'error' as const };
    if (stock < 10) return { label: 'Low Stock', variant: 'warning' as const };
    return { label: 'In Stock', variant: 'success' as const };
  }, [props.product.stock]);

  // Helper: handle add to cart
  const handleAddToCart = useCallback(() => {
    const productId = props.product.id || 'unknown';
    addToCart({ productId, quantity });
  }, [props.product.id, quantity, addToCart]);

  const isOutOfStock = props.product.stock === 0;

  // Parse specifications and reviews
  const specs = Array.isArray(props.product.specifications) ? props.product.specifications : [];
  const reviewsList = Array.isArray(props.product.reviews) ? props.product.reviews : [];

  // Build tab items for Tabs component
  // Build tab items for Tabs component
  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Box padding="var(--ggui-spacing-4)">
          <Text variant="body">{props.product.description || 'No description available'}</Text>
        </Box>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-2)">
            {specs.length > 0 ? (
              <Table
                columns={[
                  { key: 'key', header: 'Property', width: '40%' },
                  { key: 'value', header: 'Value', width: '60%' },
                ]}
                data={specs.map((spec: unknown) => {
                  if (typeof spec === 'object' && spec !== null) {
                    const specObj = spec as Record<string, unknown>;
                    return { key: specObj.key, value: specObj.value };
                  }
                  return { key: '', value: '' };
                })}
                compact
              />
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                No specifications available
              </Text>
            )}
          </Stack>
        </Box>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Box padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-4)">
            {reviewsList.length > 0 ? (
              <Stack gap="var(--ggui-spacing-3)">
                {reviewsList.map((review: unknown, idx: number) => {
                  if (typeof review === 'object' && review !== null) {
                    const rev = review as Record<string, unknown>;
                    return (
                      <Card key={idx} padding="var(--ggui-spacing-3)" shadow="sm">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Row justify="between" align="center">
                            <Stack gap="var(--ggui-spacing-1)">
                              <Text variant="label" weight="semibold">
                                {String(rev.author || 'Anonymous')}
                              </Text>
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                {String(rev.date || 'No date')}
                              </Text>
                            </Stack>
                            {renderStars(Number(rev.rating) || 0)}
                          </Row>
                          <Text variant="body">{String(rev.text || 'No comment')}</Text>
                        </Stack>
                      </Card>
                    );
                  }
                  return null;
                })}
              </Stack>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                No reviews yet
              </Text>
            )}
          </Stack>
        </Box>
      ),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* TOP SECTION: Image, Title, Price, Rating, Stock Status */}
        <Stack gap="var(--ggui-spacing-6)" direction="horizontal" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            background="var(--ggui-color-primary-50)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-6)"
            style={{ minWidth: '300px', width: '300px', height: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack align="center" gap="var(--ggui-spacing-2)">
              <Icon name="image" size={48} color="var(--ggui-color-primary-200)" />
              <Text variant="label" color="var(--ggui-color-primary-600)" align="center">
                {props.product.name || 'Product Image'}
              </Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '280px' }}>
            {/* Title */}
            <Heading level={1}>{props.product.name || 'Product Name'}</Heading>

            {/* Price */}
            <Heading level={3} color="var(--ggui-color-primary-600)">{formattedPrice}</Heading>

            {/* Rating and Review Count */}
            <Row gap="var(--ggui-spacing-3)" align="center">
              {renderStars(props.product.rating)}
              {props.product.reviewCount !== undefined && (
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  ({props.product.reviewCount} reviews)
                </Text>
              )}
            </Row>

            {/* Stock Status Badge */}
            <Badge variant={stockStatus.variant} size="md">
              {stockStatus.label}
            </Badge>
          </Stack>
        </Stack>

        {/* MIDDLE SECTION: Tabs */}
        <Tabs items={tabItems} activeKey={activeTab} onChange={setActiveTab} variant="pills" />

        {/* BOTTOM SECTION: Quantity Selector & Add to Cart */}
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center" justify="between">
            {/* Quantity Selector */}
            <Stack gap="var(--ggui-spacing-3)" direction="horizontal" align="center">
              <Text variant="label">Quantity:</Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={decrementQty}
                  disabled={quantity <= 1}
                >
                  −
                </Button>
                <Box
                  padding="0 var(--ggui-spacing-2)"
                  style={{ minWidth: '40px', textAlign: 'center' }}
                >
                  <Text variant="label" align="center">
                    {quantity}
                  </Text>
                </Box>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={incrementQty}
                  disabled={quantity >= (props.product.stock || 0)}
                >
                  +
                </Button>
              </Row>
            </Stack>

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              onClick={handleAddToCart}
              disabled={isOutOfStock}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
