interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [inputText, setInputText] = useState('');
  const [currentTypingUser, setCurrentTypingUser] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setCurrentTypingUser(typing.latest.sender || null);
      } else {
        setCurrentTypingUser(null);
      }
    }
  }, [typing.latest]);

  // Auto-scroll to bottom on new messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages, currentTypingUser]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputText.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputText, timestamp });
      // Optionally add to local list immediately for UX
      setAllMessages((prev) => [...prev, { sender: props.currentUser, text: inputText, timestamp }]);
      setInputText('');
    }
  }, [inputText, props.currentUser, sendMessage]);

  // Handle Enter key in input
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender: string; messages: typeof allMessages }> = [];
    let currentGroup: { sender: string; messages: typeof allMessages } | null = null;

    allMessages.forEach((msg) => {
      const sender = msg.sender || 'Unknown';
      if (currentGroup && currentGroup.sender === sender) {
        currentGroup.messages.push(msg);
      } else {
        if (currentGroup) groups.push(currentGroup);
        currentGroup = { sender, messages: [msg] };
      }
    });

    if (currentGroup) groups.push(currentGroup);
    return groups;
  }, [allMessages]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" radius="lg" padding="var(--ggui-spacing-4)">
        <Stack gap="var(--ggui-spacing-4)" direction="vertical">
          {/* Header */}
          <Row align="center" justify="between" gap="var(--ggui-spacing-4)">
            <Stack direction="vertical" gap="var(--ggui-spacing-1)">
              <Heading level={3}>{props.title}</Heading>
            </Stack>
            <Badge variant="primary" size="md">
              {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
            </Badge>
          </Row>

          <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

          {/* Message List */}
          <Box
            paddingY="var(--ggui-spacing-4)"
            paddingX="var(--ggui-spacing-3)"
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-md)"
            role="region"
            aria-label="Chat messages"
            style={{
              maxHeight: '400px',
              overflowY: 'auto',
              display: 'flex',
              flexDirection: 'column',
              gap: 'var(--ggui-spacing-3)',
            }}
          >
            {groupedMessages.length === 0 ? (
              <Text
                color="var(--ggui-color-onSurfaceVariant)"
                align="center"
                variant="bodySmall"
              >
                No messages yet. Start the conversation!
              </Text>
            ) : (
              groupedMessages.map((group) => {
                const isCurrentUser = group.sender === props.currentUser;
                return (
                  <Stack
                    key={`${group.sender}-${group.messages[0]?.timestamp}`}
                    direction="vertical"
                    gap="var(--ggui-spacing-2)"
                    align={isCurrentUser ? 'end' : 'start'}
                  >
                    {!isCurrentUser && (
                      <Text
                        variant="label"
                        color="var(--ggui-color-onSurfaceVariant)"
                        size="xs"
                      >
                        {group.sender}
                      </Text>
                    )}
                    {group.messages.map((msg, idx) => (
                      <Box
                        key={`${msg.timestamp}-${idx}`}
                        paddingX="var(--ggui-spacing-3)"
                        paddingY="var(--ggui-spacing-2)"
                        background={
                          isCurrentUser
                            ? 'var(--ggui-color-primary-600)'
                            : 'var(--ggui-color-surfaceVariant)'
                        }
                        borderRadius="var(--ggui-shape-radius-md)"
                        style={{
                          maxWidth: '70%',
                          wordWrap: 'break-word',
                        }}
                      >
                        <Text
                          variant="body"
                          color={
                            isCurrentUser
                              ? 'white'
                              : 'var(--ggui-color-onSurface)'
                          }
                        >
                          {msg.text}
                        </Text>
                        <Text
                          variant="caption"
                          color={
                            isCurrentUser
                              ? 'rgba(255, 255, 255, 0.7)'
                              : 'var(--ggui-color-onSurfaceVariant)'
                          }
                          style={{ marginTop: 'var(--ggui-spacing-1)' }}
                        >
                          {msg.timestamp
                            ? new Date(msg.timestamp).toLocaleTimeString([], {
                                hour: '2-digit',
                                minute: '2-digit',
                              })
                            : ''}
                        </Text>
                      </Box>
                    ))}
                  </Stack>
                );
              })
            )}
            {currentTypingUser && (
              <Stack direction="vertical" gap="var(--ggui-spacing-1)" align="start">
                <Text
                  variant="label"
                  color="var(--ggui-color-onSurfaceVariant)"
                  size="xs"
                >
                  {currentTypingUser}
                </Text>
                <Box
                  paddingX="var(--ggui-spacing-3)"
                  paddingY="var(--ggui-spacing-2)"
                  background="var(--ggui-color-surface)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Text
                    variant="body"
                    color="var(--ggui-color-onSurfaceVariant)"
                    style={{
                      fontStyle: 'italic',
                    }}
                  >
                    typing...
                  </Text>
                </Box>
              </Stack>
            )}
            <div ref={messagesEndRef} />
           </Box>
          {/* Input Area */}
          <Row gap="var(--ggui-spacing-2)" align="center">
            <Input
              label="Message"
              placeholder="Type a message..."
              value={inputText}
              onChange={setInputText}
              onKeyDown={handleKeyDown}
              style={{ flex: 1 }}
            />
            <Button
              variant="primary"
              onClick={handleSendMessage}
              disabled={!inputText.trim()}
              size="md"
              aria-label="Send message"
            >
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

