import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

const TOTAL_STEPS = 5;

const isValidEmail = (value: string): boolean => {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [currentStep, setCurrentStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({
    name: false,
    email: false,
  });

  const normalizedFeatureOptions = useMemo(() => (Array.isArray(props.featureOptions) ? props.featureOptions : []), [props.featureOptions]);
  const normalizedSatisfactionLabels = useMemo(() => (Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels : []), [props.satisfactionLabels]);

  const nameError = touched.name && name.trim().length === 0 ? 'Name is required.' : '';
  const emailError = touched.email
    ? email.trim().length === 0
      ? 'Email is required.'
      : !isValidEmail(email)
        ? 'Please enter a valid email address.'
        : ''
    : '';

  const stepValid = useMemo(() => {
    if (currentStep === 1) {
      return name.trim().length > 0 && isValidEmail(email);
    }
    if (currentStep === 2) {
      return satisfaction !== '';
    }
    return true;
  }, [currentStep, name, email, satisfaction]);

  const progressValue = useMemo(() => (currentStep / TOTAL_STEPS) * 100, [currentStep]);

  const satisfactionOptions = useMemo(
    () =>
      normalizedSatisfactionLabels.map((label, index) => ({
        value: String(index + 1),
        label: `${index + 1} - ${label}`,
      })),
    [normalizedSatisfactionLabels],
  );

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        return prev.includes(feature) ? prev : [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const goNext = useCallback(() => {
    if (currentStep === 1) {
      setTouched({ name: true, email: true });
    }
    if (!stepValid) {
      return;
    }
    setCurrentStep((prev) => (prev < TOTAL_STEPS ? prev + 1 : prev));
  }, [currentStep, stepValid]);

  const goBack = useCallback(() => {
    setCurrentStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: satisfaction === '' ? 0 : Number(satisfaction),
      features,
      comments: comments.trim(),
    });
  }, [submit, name, email, satisfaction, features, comments]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
        <Stack gap="var(--ggui-spacing-5)">
          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center">
              <Heading level={3}>Survey Form</Heading>
              <Badge variant="primary">Step {currentStep} of {TOTAL_STEPS}</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>

          {currentStep === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Input
                label="Name"
                value={name}
                onChange={setName}
                required
                error={nameError || undefined}
                placeholder="Enter your name"
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                required
                error={emailError || undefined}
                placeholder="Enter your email"
              />
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <RadioGroup
                label="How satisfied are you?"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionOptions}
                error={satisfaction === '' ? 'Please select a rating to continue.' : undefined}
              />
              {normalizedSatisfactionLabels.length === 0 && (
                <Alert variant="warning" title="No rating labels provided">
                  Satisfaction labels are currently unavailable.
                </Alert>
              )}
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack gap="var(--ggui-spacing-3)">
              <Text variant="label" color="var(--ggui-color-onSurface)">
                Which features are you interested in?
              </Text>
              {normalizedFeatureOptions.length === 0 ? (
                <Alert variant="info" title="No feature options provided">
                  There are currently no feature options to select.
                </Alert>
              ) : (
                normalizedFeatureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={(checked) => toggleFeature(feature, checked)}
                  />
                ))
              )}
            </Stack>
          )}

          {currentStep === 4 && (
            <TextArea
              label="Additional comments (optional)"
              value={comments}
              onChange={setComments}
              placeholder="Share any additional feedback"
              maxLength={500}
              showCount
              rows={6}
              helperText="Maximum 500 characters"
            />
          )}

          {currentStep === 5 && (
            <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={4}>Review your answers</Heading>
                <Divider margin="var(--ggui-spacing-2)" />
                <Text><Text is="span" weight="semibold">Name:</Text> {name || '—'}</Text>
                <Text><Text is="span" weight="semibold">Email:</Text> {email || '—'}</Text>
                <Text>
                  <Text is="span" weight="semibold">Satisfaction:</Text>{' '}
                  {satisfaction === ''
                    ? '—'
                    : `${satisfaction} - ${normalizedSatisfactionLabels[Number(satisfaction) - 1] || 'Unlabeled'}` }
                </Text>
                <Text>
                  <Text is="span" weight="semibold">Feature interests:</Text>{' '}
                  {features.length > 0 ? features.join(', ') : 'None selected'}
                </Text>
                <Text>
                  <Text is="span" weight="semibold">Comments:</Text>{' '}
                  {comments.trim().length > 0 ? comments : 'No comments provided'}
                </Text>
              </Stack>
            </Card>
          )}

          <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
            <Button variant="outline" onClick={goBack} disabled={currentStep === 1}>
              Back
            </Button>
            {currentStep < TOTAL_STEPS ? (
              <Button variant="primary" onClick={goNext} disabled={!stepValid}>
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit}>
                Submit
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

