        return prev.filter((task) => (task.id ?? '') !== incomingId);
      }

      const existingIndex = prev.findIndex((task) => (task.id ?? '') === incomingId);
      if (existingIndex >= 0) {
        const next = [...prev];
        next[existingIndex] = { ...next[existingIndex], ...incoming };
        return next;
      }

      return [...prev, incoming];
    });
  }, [taskChanged.latest]);

