    (taskId: string) => {
      const trimmed = editingTitle.trim();
      if (!trimmed) return;
      setBoardTasks((prev) => prev.map((task) => ((task.id ?? '') === taskId ? { ...task, title: trimmed } : task)));
      setEditingTaskId('');
      setEditingTitle('');
      taskUpdate({ action: 'edit', taskId, data: { column: '', title: trimmed } as { column: string } });
    },
