const CATEGORY_COLORS: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-100)',
  'alkaline earth metal': 'var(--ggui-color-warning-100)',
  lanthanide: 'var(--ggui-color-warning-50)',
  actinide: 'var(--ggui-color-error-50)',
  'transition metal': 'var(--ggui-color-primary-100)',
  'post-transition metal': 'var(--ggui-color-primary-50)',
  metalloid: 'var(--ggui-color-info-100)',
  'reactive nonmetal': 'var(--ggui-color-success-100)',
  halogen: 'var(--ggui-color-success-50)',
  'noble gas': 'var(--ggui-color-primary-200)',
  unknown: 'var(--ggui-color-surfaceVariant)',
};

function normalizeCategory(category?: string): string {
  if (!category) return 'unknown';
  return category.trim().toLowerCase().replace(/-/g, ' ');
}

function getCategoryColor(category?: string): string {
  const normalized = normalizeCategory(category);
  return CATEGORY_COLORS[normalized] || 'var(--ggui-color-surfaceVariant)';
}

export default function Component(props: Props) {
