    if (!stillVisible) {
      setSelectedAtomicNumber(null);
    }
  }, [filteredElements, selectedAtomicNumber]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return allElements.find((element) => element.atomicNumber === selectedAtomicNumber) || null;
  }, [allElements, selectedAtomicNumber]);

  const categories = useMemo(() => {
