type SpecItem = { key: string; value: string };
type ReviewItem = { author: string; rating: number; text: string; date: string };

function toSpecItem(item: unknown, index: number): SpecItem {
  if (item && typeof item === 'object') {
    const record = item as Record<string, unknown>;
    const keyValue = typeof record.key === 'string' ? record.key : `Spec ${index + 1}`;
    const valueValue = typeof record.value === 'string' ? record.value : String(record.value ?? '—');
    return { key: keyValue, value: valueValue };
  }
  return { key: `Spec ${index + 1}`, value: String(item ?? '—') };
}

function toReviewItem(item: unknown, index: number): ReviewItem {
  if (item && typeof item === 'object') {
    const record = item as Record<string, unknown>;
    return {
      author: typeof record.author === 'string' ? record.author : `Reviewer ${index + 1}`,
      rating: typeof record.rating === 'number' ? Math.max(1, Math.min(5, Math.round(record.rating))) : 1,
      text: typeof record.text === 'string' ? record.text : String(record.text ?? ''),
      date: typeof record.date === 'string' ? record.date : '',
    };
  }
  return {
    author: `Reviewer ${index + 1}`,
    rating: 1,
    text: String(item ?? ''),
    date: '',
  };
}

