  const endRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setMessageList(props.messages || []);
  }, [props.messages]);

  useEffect(() => {
    if (message.latest) {
      setMessageList((prev) => [...prev, message.latest as StreamMessage]);
    }
  }, [message.latest]);

  useEffect(() => {
    if (!typing.latest || typing.latest.active === false || !typing.latest.sender) {
      setTypingState(null);
      return;
    }
    if (typing.latest.sender === props.currentUser) {
      setTypingState(null);
      return;
    }
