    const groups: Array<{ sender?: string; messages: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    (messageList || []).forEach((item) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === item.sender) {
        lastGroup.messages.push(item);
