                    (groupedMessages || []).map((group, groupIndex) => {
                      const isOwnGroup = group.sender === props.currentUser;
                      return (
                        <Stack key={`${group.sender || 'unknown'}-${groupIndex}`} gap="var(--ggui-spacing-1)" align={isOwnGroup ? 'end' : 'start'}>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {group.sender || 'Unknown'}
                          </Text>
                          <Stack gap="var(--ggui-spacing-1)" align={isOwnGroup ? 'end' : 'start'}>
                            {(group.messages || []).map((item, itemIndex) => (
                              <Box
                                key={`${groupIndex}-${itemIndex}-${item.timestamp || 'time'}` }
                                padding="var(--ggui-spacing-3)"
                                background={isOwnGroup ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                                borderRadius="var(--ggui-shape-radius-md)"
                              >
                                <Stack gap="var(--ggui-spacing-1)">
                                  <Text
                                    variant="bodySmall"
                                    color={isOwnGroup ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                                  >
                                    {item.text || ''}
                                  </Text>
                                  <Text
                                    variant="caption"
                                    color={isOwnGroup ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                                    align={isOwnGroup ? 'right' : 'left'}
                                  >
                                    {formatTimestamp(item.timestamp)}
                                  </Text>
                                </Stack>
                              </Box>
                            ))}
                          </Stack>
                        </Stack>
                      );
                    })
                  )}
                  <Box>
                    <div ref={endRef} />
                  </Box>
                </Stack>
              </Box>
            </Stack>
          </Box>

          <Divider margin="var(--ggui-spacing-1)" />

          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                placeholder="Type a message..."
                value={draftMessage}
                onChange={setDraftMessage}
                onKeyDown={(event) => {
                  if (event.key === 'Enter' && !event.shiftKey) {
                    event.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Box>
              <Button
                as={Clickable}
                onClick={handleSend}
                variant="primary"
                disabled={!canSend}
              >
                Send
              </Button>
            </Box>
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

