// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Place helper components here if needed

function formatCurrency(value: number): string {
  return `$${value.toFixed(2)}`;
}

function formatSigned(value: number): string {
  const sign = value > 0 ? '+' : '';
  return `${sign}${value.toFixed(2)}`;
}

function formatPercent(value: number): string {
  const sign = value > 0 ? '+' : '';
  return `${sign}${value.toFixed(2)}%`;
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  const [displayStocks, setDisplayStocks] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<string>(new Date().toLocaleTimeString());
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});

  useEffect(() => {
    setDisplayStocks(props.stocks || []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setLastUpdated(new Date().toLocaleTimeString());
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }

    const symbolKey = priceUpdate.latest.symbol;
    setDisplayStocks((prev) => {
      const next = (prev || []).map((stock) => {
        if (stock.symbol !== symbolKey) {
          return stock;
        }

        return {
          ...stock,
          price: priceUpdate.latest?.price ?? stock.price,
          change: priceUpdate.latest?.change ?? stock.change,
          changePercent: priceUpdate.latest?.changePercent ?? stock.changePercent,
        };
      });

      const exists = next.some((stock) => stock.symbol === symbolKey);
      if (!exists) {
        next.push({
          symbol: priceUpdate.latest.symbol,
          name: priceUpdate.latest.symbol,
          price: priceUpdate.latest.price,
          change: priceUpdate.latest.change,
          changePercent: priceUpdate.latest.changePercent,
        });
      }
      return next;
    });

    setFlashMap((prev) => ({
      ...prev,
      [symbolKey]: Date.now(),
    }));
  }, [priceUpdate.latest]);

  useEffect(() => {
    if (!priceUpdate.latest?.symbol) {
      return;
    }
    const symbolKey = priceUpdate.latest.symbol;
    const timer = setTimeout(() => {
      setFlashMap((prev) => {
        const next = { ...prev };
        delete next[symbolKey];
        return next;
      });
    }, 700);

    return () => clearTimeout(timer);
  }, [flashMap, priceUpdate.latest]);

  const marketState = marketStatus.latest?.status || 'open';
  const marketBadgeVariant = marketState === 'open' ? 'success' : marketState === 'closed' ? 'error' : 'warning';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                Market Watch
              </Heading>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" is="div">
                <span aria-live="polite" aria-atomic="true">Last Updated: {lastUpdated}</span>
              </Text>
            </Stack>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Badge variant={marketBadgeVariant}>
                {marketState}
              </Badge>
              {marketStatus.latest?.timestamp && (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {marketStatus.latest.timestamp}
                </Text>
              )}
            </Row>
          </Row>
        </Card>

        {(!displayStocks || displayStocks.length === 0) && (
          <Alert variant="info" title="No stocks available">
            Waiting for stock data...
          </Alert>
        )}

        <Box
          role="list"
          aria-live="polite"
          aria-label="Live stock prices"
          className="stock-grid-3col"
          style={{
            display: 'grid',
            gridTemplateColumns: '1fr',
            gap: 'var(--ggui-spacing-4)',
          }}
        >
          <style>{`
            @media (min-width: 1024px) {
              .stock-grid-3col {
                grid-template-columns: repeat(3, minmax(0, 1fr));
              }
            }
          `}</style>
          {(displayStocks || []).map((stock, index) => {
            const symbol = stock.symbol || `stock-${index}`;
            const changeValue = stock.change ?? 0;
            const percentValue = stock.changePercent ?? 0;
            const isPositive = changeValue >= 0;
            const accentColor = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
            const arrow = isPositive ? '▲' : '▼';
            const shouldFlash = Boolean(flashMap[symbol]);

            return (
              <Card
                role="listitem"
                key={`${symbol}-${flashMap[symbol] || 0}`}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                border
                style={{
                  borderColor: accentColor,
                  animation: shouldFlash ? 'ggui-flash 500ms ease-out' : 'none',
                  ['--ggui-flash-color' as string]: isPositive ? 'var(--ggui-color-success-100)' : 'var(--ggui-color-error-100)',
                }}
              >
                <Stack gap="var(--ggui-spacing-2)">
                  <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface)">
                    {stock.symbol || '--'}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    {stock.name || 'Unknown Company'}
                  </Text>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Text size="2xl" weight="semibold" color="var(--ggui-color-onSurface)">
                    {formatCurrency(stock.price ?? 0)}
                  </Text>
                  <Row justify="between" align="center">
                    <Text variant="bodySmall" color={accentColor} weight="medium">
                      {formatSigned(changeValue)}
                    </Text>
                    <Text variant="bodySmall" color={accentColor} weight="medium">
                      {arrow} {formatPercent(percentValue)}
                    </Text>
                  </Row>
                </Stack>
              </Card>
            );
          })}
        </Box>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Place helper components here if needed

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(
    props.initialProfile.avatar ?? (props.avatarOptions[0] ?? '🙂')
  );
  const [role, setRole] = useState(
    props.initialProfile.role ?? (props.roleOptions[0] ?? 'Developer')
  );
  const [emailNotifications, setEmailNotifications] = useState(
    props.initialProfile.emailNotifications ?? true
  );
  const [theme, setTheme] = useState(props.initialProfile.theme ?? 'light');
  const [showErrors, setShowErrors] = useState(false);

  useEffect(() => {
    setName(props.initialProfile.name ?? '');
    setEmail(props.initialProfile.email ?? '');
    setAvatar(props.initialProfile.avatar ?? (props.avatarOptions[0] ?? '🙂'));
    setRole(props.initialProfile.role ?? (props.roleOptions[0] ?? 'Developer'));
    setEmailNotifications(props.initialProfile.emailNotifications ?? true);
    setTheme(props.initialProfile.theme ?? 'light');
  }, [props.initialProfile, props.avatarOptions, props.roleOptions]);

  const nameError = showErrors && !name.trim() ? 'Name is required.' : '';
  const emailRequiredError = showErrors && !email.trim() ? 'Email is required.' : '';
  const emailFormatError =
    showErrors && email.trim() && !EMAIL_REGEX.test(email.trim())
      ? 'Enter a valid email address.'
      : '';
  const emailError = emailRequiredError || emailFormatError;

  const isStep1Valid = useMemo(() => {
    return Boolean(name.trim()) && EMAIL_REGEX.test(email.trim()) && Boolean(avatar);
  }, [name, email, avatar]);

  const canProceed = step === 1 ? isStep1Valid : true;

  const handleNext = useCallback(() => {
    if (step === 1 && !isStep1Valid) {
      setShowErrors(true);
      return;
    }
    setShowErrors(false);
    setStep((prev) => Math.min(prev + 1, 3));
  }, [step, isStep1Valid]);

  const handleBack = useCallback(() => {
    setStep((prev) => Math.max(prev - 1, 1));
  }, []);

  const handleComplete = useCallback(() => {
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    complete(payload);
    if (typeof (props as unknown as { onComplete?: (data: ActionCompletePayload) => void }).onComplete === 'function') {
      (props as unknown as { onComplete?: (data: ActionCompletePayload) => void }).onComplete?.(payload);
    }
  }, [complete, name, email, avatar, role, emailNotifications, theme, props]);
  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={2}>Onboarding Setup</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} variant="default" size="md" />
            <Row gap="var(--ggui-spacing-2)">
              {[1, 2, 3].map((s) => (
                <Box
                  key={s}
                  padding="var(--ggui-spacing-2)"
                  background={step >= s ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Text
                    variant="label"
                    color={step >= s ? 'var(--ggui-color-primary-700)' : 'var(--ggui-color-onSurfaceVariant)'}
                  >
                    {s === 1 ? 'Profile' : s === 2 ? 'Preferences' : 'Review'}
                  </Text>
                </Box>
              ))}
            </Row>
          </Stack>
        </Card>

        <Card
          key={step}
          padding="var(--ggui-spacing-6)"
          shadow="sm"
        >
          <Stack gap="var(--ggui-spacing-4)" style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Profile Setup</Heading>
                <Input
                  label="Name"
                  placeholder="Enter your full name"
                  value={name}
                  onChange={setName}
                  required
                  error={nameError}
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="you@example.com"
                  value={email}
                  onChange={setEmail}
                  required
                  error={emailError}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose an avatar</Text>
                  <Row gap="var(--ggui-spacing-2)" wrap>
                    {(props.avatarOptions.length ? props.avatarOptions : ['🙂', '😎', '🚀', '🎨']).slice(0, 4).map((option) => (
                      <Card
                        key={option}
                        as={Clickable}
                        onClick={() => setAvatar(option)}
                        padding="var(--ggui-spacing-3)"
                        border
                        shadow="none"
                        radius="md"
                        hoverStyle={{ opacity: 0.9 }}
                        role="button"
                        tabIndex={0}
                        aria-label={`Select avatar ${option}`}
                        aria-pressed={avatar === option}
                      >
                        <Stack align="center" gap="var(--ggui-spacing-1)">
                          <Text size="2xl">{option}</Text>
                          {avatar === option && <Badge variant="success" size="sm">Selected</Badge>}
                        </Stack>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={(props.roleOptions.length ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other']).map((r) => ({ value: r, label: r }))}
                  placeholder="Select your role"
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Theme preference (dark mode)"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Review & Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
                <Alert variant="info" title="Ready to finish">
                  Review your details, then complete setup.
                </Alert>
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />
            <Row justify="between" align="center">
              <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
                Back
              </Button>
              {step < 3 ? (
                <Button variant="primary" onClick={handleNext} disabled={!canProceed}>
                  Next
                </Button>
              ) : (
                <Row gap="var(--ggui-spacing-2)">
                  <Button variant="outline" onClick={handleBack}>Go Back</Button>
                  <Button variant="primary" onClick={handleComplete}>Complete Setup</Button>
                </Row>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}
